export function buildCatalogListToolbarActions(p) {
    const prefix = p.testIdPrefix;
    const deleteLabel = p.selectedCount && p.selectedCount > 0
        ? `Xóa (${p.selectedCount})`
        : undefined;
    return [
        {
            id: 'refresh',
            placement: 'left',
            action: 'refresh',
            visible: true,
            onClick: p.onRefresh,
            testId: `${prefix}-toolbar-refresh-btn`,
        },
        {
            id: 'history',
            placement: 'left',
            action: 'history',
            visible: p.canHistory,
            disabled: !p.canHistory,
            onClick: p.onHistory,
            testId: `${prefix}-toolbar-history-btn`,
        },
        {
            id: 'editConfig',
            placement: 'left',
            action: 'editConfig',
            visible: Boolean(p.showSchemaConfig ?? p.onEditConfig),
            onClick: p.onEditConfig,
            testId: `${prefix}-list-config-btn`,
        },
        {
            id: 'rename',
            placement: 'right',
            action: 'renameCode',
            bundleOnCompact: true,
            visible: Boolean(p.showEdit && p.canRename),
            onClick: p.onRename,
            testId: `${prefix}-rename-code-btn`,
        },
        {
            id: 'view',
            placement: 'right',
            action: 'view',
            visible: Boolean(p.showView),
            onClick: p.onView,
            testId: `${prefix}-toolbar-view-btn`,
        },
        {
            id: 'edit',
            placement: 'right',
            action: 'edit',
            visible: Boolean(p.showEdit),
            onClick: p.onEdit,
            testId: `${prefix}-toolbar-edit-btn`,
        },
        {
            id: 'delete',
            placement: 'right',
            action: 'delete',
            bundleOnCompact: true,
            label: deleteLabel,
            visible: Boolean(p.showEdit && p.canDelete),
            onClick: p.onDelete,
            testId: `${prefix}-batch-delete-btn`,
        },
        {
            id: 'create',
            placement: 'right',
            action: 'create',
            variant: 'primary',
            visible: p.canAdd !== false,
            onClick: p.onAdd,
            testId: `${prefix}-toolbar-add-btn`,
        },
    ];
}
